import warnings
from dataclasses import dataclass


@dataclass(frozen=True)
class MapQuery:
    """Query to retrieve complete ways and relations in an area."""

    south: float
    west: float
    north: float
    east: float

    _QUERY_TEMPLATE = "(node({south},{west},{north},{east});<;>;);"

    def __post_init__(self):
        warnings.warn(
            "overpass.MapQuery is deprecated and will be removed in overpass 1.0; "
            "use overpass.recipes.bbox_geometry(BBox(...)) in 1.0 instead.",
            DeprecationWarning,
            stacklevel=2,
        )

    def __str__(self):
        return self._QUERY_TEMPLATE.format(
            west=self.west, south=self.south, east=self.east, north=self.north
        )


@dataclass(frozen=True)
class WayQuery:
    """Query to retrieve a set of ways and their dependent nodes satisfying the input parameters."""

    query_parameters: str

    _QUERY_TEMPLATE = "(way{query_parameters});(._;>;);"

    def __post_init__(self):
        warnings.warn(
            "overpass.WayQuery is deprecated and will be removed in overpass 1.0; "
            "use overpass.recipes.ways_with_nodes(Query.ways().raw(...)) in 1.0 instead.",
            DeprecationWarning,
            stacklevel=2,
        )

    def __str__(self):
        return self._QUERY_TEMPLATE.format(query_parameters=self.query_parameters)
